def _wave_unit(dev: wave3.Device):
    match dev:
        case wave3.Device:
            return (
                UnitOfTemperature.FAHRENHEIT
                if dev.temp_unit is wave3.TemperatureUnit.FAHRENHEIT
                else UnitOfTemperature.CELSIUS
            )
    return UnitOfTemperature.CELSIUS

