def _liquefied_gas_unit(dev: DeviceBase) -> str:
    unit = getattr(dev, "liquefied_gas_unit", None)
    if (
        unit is not None
        and getattr(unit, "value", -1) == smart_generator.LiquefiedGasUnit.LB.value
    ):
        return UnitOfMass.POUNDS
    return UnitOfMass.KILOGRAMS

